final:
module RefModule (
  input clk,
  input en,
  input rst,
  output reg [5:0] count);

  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge rst or posedge dbg_halt) begin
    if (rst)
        count <= 6'b000001;
    else if (en)
        count <= {count[4:0], count[5]};
end
endmodule
